import React from 'react';
import Card from '../Card';

const RiskLevelBar: React.FC<{ level: number }> = ({ level }) => {
  const totalBars = 18;
  return (
    <div className="flex gap-1 items-center">
      {Array.from({ length: totalBars }).map((_, i) => {
        let color = 'bg-slate-600';
        if (i < level) {
          if (i < totalBars * 0.6) color = 'bg-emerald-500';
          else if (i < totalBars * 0.8) color = 'bg-yellow-500';
          else color = 'bg-red-500';
        }
        if (i === level - 1) {
            return <div key={i} className={`h-4 w-4 rounded-sm ${color} shadow-[0_0_10px] shadow-emerald-400`}></div>
        }
        return <div key={i} className={`h-2 flex-1 rounded-full ${color}`}></div>;
      })}
    </div>
  );
};


