const getColor = (value: number) => {
  if (value >= 8) return 'bg-emerald-500/80';
  if (value >= 6) return 'bg-lime-500/80';
  if (value >= 4) return 'bg-yellow-500/80';
  if (value >= 2) return 'bg-orange-500/80';
  return 'bg-red-500/80';
};

