import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import DashboardPage from './pages/DashboardPage';
import BetsPage from './pages/BetsPage';
import StatisticsPage from './pages/StatisticsPage';
import SettingsPage from './pages/SettingsPage';
import { Bet, DashboardKPIs } from './types';
import { getBets, addBet, calculateDashboardKPIs } from './services/api';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('Dashboard');
  const [bets, setBets] = useState<Bet[]>([]);
  const [kpis, setKpis] = useState<DashboardKPIs | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);
      const fetchedBets = await getBets();
      setBets(fetchedBets);
      const calculatedKpis = calculateDashboardKPIs(fetchedBets);
      setKpis(calculatedKpis);
      setIsLoading(false);
    };
    fetchData();
  }, []);

  const handleAddBet = async (newBetData: Omit<Bet, 'id' | 'profit'>) => {
    const newBet = await addBet(newBetData);
    const updatedBets = [newBet, ...bets];
    setBets(updatedBets);
    const calculatedKpis = calculateDashboardKPIs(updatedBets);
    setKpis(calculatedKpis);
  };

  const renderPage = () => {
    if (isLoading) {
        return <div className="flex-1 flex items-center justify-center"><p className="text-xl">Carregando dados...</p></div>;
    }
    switch (currentPage) {
      case 'Dashboard':
        return <DashboardPage kpis={kpis} recentBets={bets.slice(0, 4)} />;
      case 'Apostas':
        return <BetsPage bets={bets} onAddBet={handleAddBet} />;
      case 'Estatísticas':
        return <StatisticsPage bets={bets} />;
      case 'Configurações':
        return <SettingsPage />;
      default:
        return <DashboardPage kpis={kpis} recentBets={bets.slice(0, 4)} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-900 font-sans">
      <Sidebar activeItem={currentPage} onNavigate={setCurrentPage} />
      <main className="flex-1 p-4 sm:p-6 lg:p-8 overflow-y-auto">
        <div className="w-full max-w-7xl mx-auto">
          {renderPage()}
        </div>
      </main>
    </div>
  );
};

export default App;

