const INITIAL_BANKROLL = 10000;

let bets: Bet[] = [
  { id: 1, date: '23/04', game: 'Corinthians vs Palmeiras', market: 'Over 2.5', odd: 1.80, stake: 200, status: 'won', profit: 160, ev: 12 },
  { id: 2, date: '21/04', game: 'Flamengo vs Botafogo', market: 'BTTS', odd: 2.10, stake: 150, status: 'lost', profit: -150, ev: -8 },
  { id: 3, date: '19/04', game: 'São Paulo vs Santos', market: 'Handicap -1.5', odd: 2.25, stake: 100, status: 'won', profit: 125, ev: 15 },
  { id: 4, date: '18/04', game: 'Vasco vs Fluminense', market: 'Under 2.5', odd: 1.75, stake: 100, status: 'lost', profit: -100, ev: -6 },
];

// Simulate API delay
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

export const getBets = async (): Promise<Bet[]> => {
  await delay(500);
  return [...bets].sort((a, b) => b.id - a.id);
};

export const addBet = async (betData: Omit<Bet, 'id' | 'profit'>): Promise<Bet> => {
    await delay(300);
    const profit = betData.status === 'won' ? betData.stake * (betData.odd - 1) : -betData.stake;
    const newBet: Bet = {
        ...betData,
        id: Math.max(0, ...bets.map(b => b.id)) + 1,
        profit,
    };
    bets.unshift(newBet);
    return newBet;
};

export const calculateDashboardKPIs = (allBets: Bet[]): DashboardKPIs => {
    const totalProfit = allBets.reduce((sum, bet) => sum + bet.profit, 0);
    const totalStaked = allBets.reduce((sum, bet) => sum + bet.stake, 0);
    const wonBets = allBets.filter(b => b.status === 'won').length;
    const concludedBets = allBets.filter(b => b.status !== 'pending').length;

    const roi = totalStaked > 0 ? (totalProfit / totalStaked) * 100 : 0;
    const winRate = concludedBets > 0 ? (wonBets / concludedBets) * 100 : 0;

    return {
        currentBankroll: INITIAL_BANKROLL + totalProfit,
        totalProfit,
        roi,
        winRate,
        maxDrawdown: -15.7, // Placeholder
    };
};

export const calculateRoiByMarket = (allBets: Bet[]): RoiByMarket[] => {
    const marketStats: { [key: string]: { profit: number; stake: number } } = {};

    allBets.forEach(bet => {
        if (!marketStats[bet.market]) {
            marketStats[bet.market] = { profit: 0, stake: 0 };
        }
        marketStats[bet.market].profit += bet.profit;
        marketStats[bet.market].stake += bet.stake;
    });

    return Object.entries(marketStats).map(([market, stats]) => ({
        market,
        roi: stats.stake > 0 ? (stats.profit / stats.stake) * 100 : 0,
    }));
};

