import { Bet, BankrollStats, GrowthData, ProjectionConfig } from '../types';

const INITIAL_BANKROLL = 10000;

let bets: Bet[] = [
  { id: '1', date: '2025-05-10', game: 'Real Madrid vs Man City', market: 'Over 2.5', odd: 1.80, stake: 200, result: 360, profit: 160, ev: 12, status: 'won' },
  { id: '2', date: '2025-05-09', game: 'Lakers vs Warriors', market: 'ML Warriors', odd: 2.10, stake: 150, result: 0, profit: -150, ev: -8, status: 'lost' },
  { id: '3', date: '2025-05-08', game: 'Nadal vs Alcaraz', market: 'Alcaraz 2-0', odd: 2.25, stake: 100, result: 225, profit: 125, ev: 15, status: 'won' },
  { id: '4', date: '2025-05-07', game: 'PSG vs Dortmund', market: 'Under 3.5', odd: 1.75, stake: 100, result: 0, profit: -100, ev: -6, status: 'lost' },
];

export const api = {
  getBets: async () => bets,

  getBankrollStats: async (): Promise<BankrollStats> => {
    const totalProfit = bets.reduce((acc, b) => acc + b.profit, 0);
    const current = INITIAL_BANKROLL + totalProfit;
    const totalStaked = bets.reduce((acc, b) => acc + b.stake, 0);

    return {
      current,
      initial: INITIAL_BANKROLL,
      growthPct: (totalProfit / INITIAL_BANKROLL) * 100,
      drawdown: -4.2, // Mocked drawdown
      roi: totalStaked > 0 ? (totalProfit / totalStaked) * 100 : 0,
      totalProfit
    };
  },

  getGrowthProjection: async (config: ProjectionConfig): Promise<GrowthData[]> => {
    const data: GrowthData[] = [];
    let current = INITIAL_BANKROLL;
    const dailyRate = 1 + (config.dailyTargetPct / 100);

    for (let i = 0; i <= config.horizonDays; i += Math.max(1, Math.floor(config.horizonDays / 10))) {
      const projected = INITIAL_BANKROLL * Math.pow(dailyRate, i);
      data.push({
        name: `Dia ${i}`,
        bank: i === 0 ? INITIAL_BANKROLL : 0, // Simplified for visual
        projected: projected
      });
    }
    return data;
  }
};

