import { Bet, BankrollStats, GrowthData, ProjectionConfig, MarketStats } from '../types';

const INITIAL_BANKROLL = 10000;

let bets: Bet[] = [
  { id: '1', date: '2025-05-10', game: 'Real Madrid vs Man City', market: 'Over 2.5', odd: 1.80, stake: 200, result: 360, profit: 160, ev: 12, status: 'won' },
  { id: '2', date: '2025-05-09', game: 'Lakers vs Warriors', market: 'ML Warriors', odd: 2.10, stake: 150, result: 0, profit: -150, ev: -8, status: 'lost' },
  { id: '3', date: '2025-05-08', game: 'Nadal vs Alcaraz', market: 'Alcaraz 2-0', odd: 2.25, stake: 100, result: 225, profit: 125, ev: 15, status: 'won' },
  { id: '4', date: '2025-05-07', game: 'PSG vs Dortmund', market: 'Under 3.5', odd: 1.75, stake: 100, result: 0, profit: -100, ev: -6, status: 'lost' },
  { id: '5', date: '2025-05-06', game: 'Arsenal vs Bayern', market: 'Over 2.5', odd: 1.90, stake: 200, result: 380, profit: 180, ev: 5, status: 'won' },
  { id: '6', date: '2025-05-05', game: 'Liverpool vs Spurs', market: 'BTTS', odd: 1.65, stake: 150, result: 247.5, profit: 97.5, ev: 4, status: 'won' },
];

export const api = {
  getBets: async () => bets,

  getBankrollStats: async (): Promise<BankrollStats> => {
    const totalProfit = bets.reduce((acc, b) => acc + b.profit, 0);
    const current = INITIAL_BANKROLL + totalProfit;
    const totalStaked = bets.reduce((acc, b) => acc + b.stake, 0);

    return {
      current,
      initial: INITIAL_BANKROLL,
      growthPct: (totalProfit / INITIAL_BANKROLL) * 100,
      drawdown: -4.2,
      roi: totalStaked > 0 ? (totalProfit / totalStaked) * 100 : 0,
      totalProfit
    };
  },

  getGrowthProjection: async (config: ProjectionConfig): Promise<GrowthData[]> => {
    const data: GrowthData[] = [];
    const dailyRate = 1 + (config.dailyTargetPct / 100);

    for (let i = 0; i <= config.horizonDays; i += Math.max(1, Math.floor(config.horizonDays / 10))) {
      const projected = INITIAL_BANKROLL * Math.pow(dailyRate, i);
      data.push({
        name: `Dia ${i}`,
        bank: i === 0 ? INITIAL_BANKROLL : 0,
        projected: projected
      });
    }
    return data;
  },

  getMarketStats: async (): Promise<MarketStats[]> => {
    const marketMap = new Map<string, Bet[]>();
    bets.forEach(bet => {
      const list = marketMap.get(bet.market) || [];
      list.push(bet);
      marketMap.set(bet.market, list);
    });

    const results: MarketStats[] = Array.from(marketMap.entries()).map(([market, marketBets]) => {
      const totalStake = marketBets.reduce((acc, b) => acc + b.stake, 0);
      const totalProfit = marketBets.reduce((acc, b) => acc + b.profit, 0);
      const wins = marketBets.filter(b => b.status === 'won').length;
      const totalEV = marketBets.reduce((acc, b) => acc + b.ev, 0);

      const roi = (totalProfit / totalStake) * 100;
      const winRate = (wins / marketBets.length) * 100;
      const evAverage = totalEV / marketBets.length;

      // Calculate a normalized score 0-100
      // Simple formula: ROI weight 40%, WinRate 30%, EV 30%
      const score = Math.min(100, Math.max(0, (roi * 2) + (winRate * 0.5) + (evAverage * 2)));

      return {
        market,
        roi,
        winRate,
        profit: totalProfit,
        evAverage,
        volume: marketBets.length,
        drawdown: -5.5, // Mocked per market drawdown
        score
      };
    });

    return results.sort((a, b) => b.score - a.score);
  }
};

