import { Bet, BankrollStats, GrowthData, ProjectionConfig, MarketStats, Market, BankrollConfig } from '../types';

let bankConfig: BankrollConfig = {
  initialBank: 10000,
  dailyInterest: 2,
  periodDays: 30
};

let markets: Market[] = [
  { id: 'm1', name: 'Over 2.5', category: 'Gols', type: 'Back', isActive: true, createdAt: '2025-01-01' },
  { id: 'm2', name: 'BTTS', category: 'Gols', type: 'Ambos', isActive: true, createdAt: '2025-01-02' },
  { id: 'm3', name: 'Handicap -1.5', category: 'Handicap', type: 'Back', isActive: true, createdAt: '2025-01-03' },
  { id: 'm4', name: 'Under 3.5', category: 'Gols', type: 'Back', isActive: true, createdAt: '2025-01-04' },
  { id: 'm5', name: 'ML Favorito', category: 'Resultado Final', type: 'Back', isActive: true, createdAt: '2025-01-05' },
];

let bets: Bet[] = [
  { id: '1', date: new Date().toISOString().split('T')[0], game: 'Real Madrid vs Man City', marketId: 'm1', odd: 1.80, stake: 200, result: 360, profit: 160, ev: 12, status: 'won' },
  { id: '2', date: new Date().toISOString().split('T')[0], game: 'Lakers vs Warriors', marketId: 'm5', odd: 2.10, stake: 150, result: 0, profit: -150, ev: -8, status: 'lost' },
  { id: '3', date: '2025-05-08', game: 'Nadal vs Alcaraz', marketId: 'm3', odd: 2.25, stake: 100, result: 225, profit: 125, ev: 15, status: 'won' },
  { id: '4', date: '2025-05-07', game: 'PSG vs Dortmund', marketId: 'm4', odd: 1.75, stake: 100, result: 0, profit: -100, ev: -6, status: 'lost' },
];

const calculateProfit = (stake: number, odd: number, status: Bet['status']): number => {
  if (status === 'won') return (stake * odd) - stake;
  if (status === 'lost') return -stake;
  return 0;
};

const calculateResult = (stake: number, odd: number, status: Bet['status']): number => {
  if (status === 'won') return stake * odd;
  if (status === 'lost') return 0;
  return 0;
};

export const api = {
  getBankConfig: async () => ({ ...bankConfig }),
  updateBankConfig: async (config: BankrollConfig) => {
    bankConfig = { ...config };
    return bankConfig;
  },

  getMarkets: async () => [...markets],
  addMarket: async (market: Omit<Market, 'id' | 'createdAt'>) => {
    const newMarket: Market = { ...market, id: `m${Date.now()}`, createdAt: new Date().toISOString() };
    markets.push(newMarket);
    return newMarket;
  },
  toggleMarketStatus: async (id: string) => {
    markets = markets.map(m => m.id === id ? { ...m, isActive: !m.isActive } : m);
  },

  getBets: async () => {
    return bets.map(b => ({
      ...b,
      marketName: markets.find(m => m.id === b.marketId)?.name || 'Desconhecido'
    })).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  },

  addBet: async (bet: Omit<Bet, 'id' | 'profit' | 'result'>) => {
    const profit = calculateProfit(bet.stake, bet.odd, bet.status);
    const result = calculateResult(bet.stake, bet.odd, bet.status);
    const newBet: Bet = { ...bet, id: Date.now().toString(), profit, result };
    bets.push(newBet);
    return newBet;
  },

  updateBet: async (id: string, betData: Partial<Bet>) => {
    bets = bets.map(b => {
      if (b.id === id) {
        const updated = { ...b, ...betData };
        updated.profit = calculateProfit(updated.stake, updated.odd, updated.status);
        updated.result = calculateResult(updated.stake, updated.odd, updated.status);
        return updated;
      }
      return b;
    });
  },

  updateBetStatus: async (id: string, status: Bet['status']) => {
    bets = bets.map(b => {
      if (b.id === id) {
        return {
          ...b,
          status,
          profit: calculateProfit(b.stake, b.odd, status),
          result: calculateResult(b.stake, b.odd, status)
        };
      }
      return b;
    });
  },

  deleteBet: async (id: string) => {
    bets = bets.filter(b => b.id !== id);
  },

  getBankrollStats: async (): Promise<BankrollStats> => {
    const totalProfit = bets.reduce((acc, b) => acc + b.profit, 0);
    const current = bankConfig.initialBank + totalProfit;
    const totalStaked = bets.reduce((acc, b) => acc + b.stake, 0);
    const today = new Date().toISOString().split('T')[0];
    const todayProfit = bets.filter(b => b.date === today).reduce((acc, b) => acc + b.profit, 0);

    return {
      current,
      initial: bankConfig.initialBank,
      growthPct: (totalProfit / bankConfig.initialBank) * 100,
      drawdown: -4.2,
      roi: totalStaked > 0 ? (totalProfit / totalStaked) * 100 : 0,
      totalProfit,
      todayProfit
    };
  },

  getGrowthProjection: async (config: ProjectionConfig): Promise<GrowthData[]> => {
    const data: GrowthData[] = [];
    const dailyRate = 1 + (config.dailyTargetPct / 100);
    for (let i = 0; i <= config.horizonDays; i += Math.max(1, Math.floor(config.horizonDays / 10))) {
      const projected = bankConfig.initialBank * Math.pow(dailyRate, i);
      data.push({ name: `Dia ${i}`, bank: i === 0 ? bankConfig.initialBank : 0, projected: projected });
    }
    return data;
  },

  getMarketStats: async (): Promise<MarketStats[]> => {
    const marketMap = new Map<string, Bet[]>();
    bets.forEach(bet => {
      const list = marketMap.get(bet.marketId) || [];
      list.push(bet);
      marketMap.set(bet.marketId, list);
    });

    const results: MarketStats[] = Array.from(marketMap.entries()).map(([marketId, marketBets]) => {
      const marketObj = markets.find(m => m.id === marketId);
      const totalStake = marketBets.reduce((acc, b) => acc + b.stake, 0);
      const totalProfit = marketBets.reduce((acc, b) => acc + b.profit, 0);
      const wins = marketBets.filter(b => b.status === 'won').length;
      const roi = (totalProfit / totalStake) * 100;
      const winRate = (wins / marketBets.length) * 100;
      const score = (roi * 0.4) + (winRate * 0.3) - (5.0 * 0.3);

      return {
        marketId,
        marketName: marketObj?.name || 'Inativo',
        roi,
        winRate,
        profit: totalProfit,
        evAverage: marketBets.reduce((acc, b) => acc + b.ev, 0) / marketBets.length,
        volume: marketBets.length,
        drawdown: -5.0,
        score: Math.max(0, Math.min(100, score * 2)),
        category: marketObj?.category || 'N/A'
      };
    });
    return results.sort((a, b) => b.score - a.score);
  }
};

import React, { useState } from 'react';
import { Bet, Market } from '../../types';
import Card from '../Card';
import { api } from '../../services/api';

interface BetHistoryTableProps {
  dynamicBets?: Bet[];
  markets?: Market[];
  onUpdate?: () => void;
}

const BetHistoryTable: React.FC<BetHistoryTableProps> = ({ dynamicBets, markets = [], onUpdate }) => {
  const [editingBet, setEditingBet] = useState<Bet | null>(null);
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null);

  const displayBets = dynamicBets || [];

  const handleStatusChange = async (betId: string, status: Bet['status']) => {
    await api.updateBetStatus(betId, status);
    setActiveDropdown(null);
    if (onUpdate) onUpdate();
  };

  const handleDelete = async (betId: string) => {
    if (window.confirm('Deseja realmente excluir esta aposta? O impacto na banca será revertido.')) {
      await api.deleteBet(betId);
      if (onUpdate) onUpdate();
    }
  };

  const handleEditSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingBet) {
      await api.updateBet(editingBet.id, editingBet);
      setEditingBet(null);
      if (onUpdate) onUpdate();
    }
  };

  return (
    <Card>
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-bold text-white">Histórico de Apostas</h2>
        <div className="flex items-center gap-2">
           <span className="text-[10px] text-slate-500 uppercase font-bold bg-slate-700/30 px-2 py-1 rounded">
             {displayBets.length} Operações
           </span>
        </div>
      </div>

