import React, { useState, useEffect, useMemo } from 'react';
import BetHistoryTable from '../components/widgets/BetHistoryTable';
import Card from '../components/Card';
import { api } from '../services/api';
import { Bet, Market } from '../types';

const BetsPage: React.FC = () => {
  const [bets, setBets] = useState<Bet[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [statusFilter, setStatusFilter] = useState<'all' | 'won' | 'lost' | 'pending'>('all');
  const [searchQuery, setSearchQuery] = useState('');

  // New Bet Form State
  const [newBet, setNewBet] = useState({
    game: '',
    marketId: '',
    odd: 2.00,
    stake: 100,
    probability: 50.00, // User's final estimated probability
    minute: 0, // Game minute
    status: 'pending' as Bet['status'],
    date: new Date().toISOString().split('T')[0],
  });

  const load = async () => {
    const [b, m] = await Promise.all([api.getBets(), api.getMarkets()]);
    setBets(b);
    const activeMarkets = m.filter(mark => mark.isActive);
    setMarkets(activeMarkets);
    if (activeMarkets.length > 0 && !newBet.marketId) {
       setNewBet(prev => ({ ...prev, marketId: activeMarkets[0].id }));
    }
  };

  useEffect(() => {
    load();
  }, []);

  const handleOddChange = (value: number) => {
    const implied = value > 0 ? (1 / value) * 100 : 0;
    // When odd changes, we reset the estimate to the implied prob (time-adjusted if minute > 0)
    const timeRemaining = Math.max(0, 90 - newBet.minute);
    const timeFactor = timeRemaining / 90;
    const adjusted = implied * (newBet.minute > 0 ? timeFactor : 1);

    setNewBet({ 
      ...newBet, 
      odd: value, 
      probability: Number(adjusted.toFixed(2))
    });
  };

  const handleMinuteChange = (min: number) => {
    const implied = newBet.odd > 0 ? (1 / newBet.odd) * 100 : 0;
    const timeRemaining = Math.max(0, 90 - min);
    const timeFactor = timeRemaining / 90;
    const adjusted = implied * (min > 0 ? timeFactor : 1);

    setNewBet({
      ...newBet,
      minute: min,
      probability: Number(adjusted.toFixed(2)) // Auto-suggest probability based on time decay
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    await api.addBet({
      ...newBet
    });
    setIsFormOpen(false);
    load();
  };

  // Metrics calculation
  const impliedProb = newBet.odd > 0 ? (1 / newBet.odd) * 100 : 0;
  const timeRemaining = Math.max(0, 90 - newBet.minute);
  const timeFactor = timeRemaining / 90;
  const timeAdjustedImplied = newBet.minute > 0 ? impliedProb * timeFactor : impliedProb;

  const calculatedEV = ((newBet.probability / 100) * newBet.odd - 1) * 100;
  const fairOdd = newBet.probability > 0 ? (100 / newBet.probability).toFixed(2) : '0.00';
  const advantage = newBet.probability - timeAdjustedImplied;

  // Computed filtered bets
  const filteredBets = useMemo(() => {
    return bets.filter(bet => {
      const matchesStatus = statusFilter === 'all' || bet.status === statusFilter;
      const matchesSearch = bet.game.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           (bet.marketName && bet.marketName.toLowerCase().includes(searchQuery.toLowerCase()));
      return matchesStatus && matchesSearch;
    });
  }, [bets, statusFilter, searchQuery]);

  return (
    <div className="flex flex-col gap-6">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-2">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
            <span className="text-emerald-400">⚡</span> Minhas Apostas
          </h1>
          <p className="text-slate-400">Modelagem probabilística ajustada ao tempo e gestão de valor.</p>
        </div>
        <button 
          onClick={() => setIsFormOpen(!isFormOpen)}
          className={`px-6 py-2 rounded-lg font-bold transition-all transform active:scale-95 shadow-lg flex items-center gap-2 ${
            isFormOpen ? 'bg-slate-800 text-white' : 'bg-emerald-500 hover:bg-emerald-600 text-slate-900 shadow-emerald-500/20'
          }`}
        >
          {isFormOpen ? '✖ Fechar' : '➕ Nova Operação'}
        </button>
      </header>

      {isFormOpen && (
        <Card className="animate-in slide-in-from-top duration-300 border-emerald-500/20">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-xl font-bold text-white">Registrar Nova Operação</h2>
            {newBet.minute > 70 && (
              <span className="bg-red-500/20 text-red-400 text-[10px] font-black uppercase px-3 py-1 rounded-full border border-red-500/30 animate-pulse">
                ⚠️ Alta Sensibilidade ao Tempo
              </span>
            )}
          </div>

          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-6">
            <div className="md:col-span-2">
              <label className="text-xs text-slate-500 uppercase mb-1 block font-bold">Evento / Jogo</label>
              <input 
                type="text" 
                required
                value={newBet.game}
                onChange={(e) => setNewBet({ ...newBet, game: e.target.value })}
                placeholder="Ex: Real Madrid vs Man City"
                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white outline-none focus:border-emerald-500 transition-all shadow-inner"
              />
            </div>
            <div>
              <label className="text-xs text-slate-500 uppercase mb-1 block font-bold">Mercado Estratégico</label>
              <select 
                required
                value={newBet.marketId}
                onChange={(e) => setNewBet({ ...newBet, marketId: e.target.value })}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white outline-none focus:border-emerald-500 cursor-pointer shadow-inner"
              >
                {markets.map(m => (
                  <option key={m.id} value={m.id}>{m.name}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="text-xs text-slate-500 uppercase mb-1 block font-bold">Data</label>
              <input 
                type="date" 
                value={newBet.date}
                onChange={(e) => setNewBet({ ...newBet, date: e.target.value })}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white outline-none focus:border-emerald-500"
              />
            </div>

            {/* Modeling Block */}
            <div className="md:col-span-3 lg:col-span-4 grid grid-cols-1 md:grid-cols-5 gap-4 bg-slate-950/60 p-5 rounded-2xl border border-slate-800 shadow-xl">
               <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase block font-bold">Tempo (Minuto)</label>
                  <input 
                    type="number" min="0" max="100"
                    value={newBet.minute}
                    onChange={(e) => handleMinuteChange(Number(e.target.value))}
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white outline-none focus:border-emerald-500 font-mono text-xl"
                  />
                  <div className="flex justify-between px-1">
                    <span className="text-[10px] text-slate-500 uppercase">Restante</span>
                    <span className="text-[10px] text-slate-300 font-bold">{timeRemaining}m</span>
                  </div>
               </div>

               <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase block font-bold">Odd Atual</label>
                  <input 
                    type="number" step="0.01" 
                    value={newBet.odd}
                    onChange={(e) => handleOddChange(Number(e.target.value))}
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white outline-none focus:border-emerald-500 font-mono text-xl"
                  />
                  <div className="flex justify-between px-1">
                    <span className="text-[10px] text-slate-500 uppercase">Ajustada</span>
                    <span className="text-[10px] text-slate-300 font-bold">{timeAdjustedImplied.toFixed(1)}%</span>
                  </div>
               </div>

               <div className="space-y-1">
                  <label className="text-[10px] text-slate-400 uppercase block font-bold tracking-wider">Sua Probabilidade (%)</label>
                  <input 
                    type="number" step="0.1"
                    value={newBet.probability}
                    min="0" max="100"
                    onChange={(e) => setNewBet({ ...newBet, probability: Number(e.target.value) })}
                    className="w-full bg-slate-900 border border-emerald-500/30 rounded-lg px-4 py-3 text-emerald-400 outline-none focus:border-emerald-500 font-mono text-xl font-bold shadow-[0_0_10px_rgba(16,185,129,0.05)]"
                  />
                  <div className="flex justify-between px-1">
                    <span className="text-[10px] text-slate-500 uppercase">Vantagem</span>
                    <span className={`text-[10px] font-bold ${advantage >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                      {advantage >= 0 ? '+' : ''}{advantage.toFixed(1)}%
                    </span>
                  </div>
               </div>

               <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase block font-bold">Stake (R$)</label>
                  <input 
                    type="number" step="1" 
                    value={newBet.stake}
                    onChange={(e) => setNewBet({ ...newBet, stake: Number(e.target.value) })}
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white outline-none focus:border-emerald-500 font-mono text-xl"
                  />
                  <div className="flex justify-between px-1">
                    <span className="text-[10px] text-slate-500 uppercase">Odd Justa</span>
                    <span className="text-[10px] text-slate-300 font-bold">@{fairOdd}</span>
                  </div>
               </div>

               <div className="flex flex-col justify-center items-center md:items-end px-4 border-l border-slate-800">
                  <div className="text-right">
                    <p className="text-[10px] text-slate-500 uppercase font-bold mb-1">EV Real (Ajustado)</p>
                    <div className="flex items-center gap-2">
                       <p className={`text-4xl font-black tracking-tighter ${calculatedEV >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                        {calculatedEV >= 0 ? '+' : ''}{calculatedEV.toFixed(1)}%
                       </p>
                    </div>
                    <p className="text-[10px] text-slate-500 mt-1 uppercase font-bold tracking-widest">
                      {calculatedEV >= 10 ? '💎 VALOR ALTO' : calculatedEV >= 0 ? '✅ VALOR POSITIVO' : '⚠️ EV NEGATIVO'}
                    </p>
                  </div>
               </div>
            </div>

            <div>
              <label className="text-xs text-slate-500 uppercase mb-1 block font-bold">Status Inicial</label>
              <div className="flex gap-2 h-10">
                {['pending', 'won', 'lost'].map(st => (
                  <button 
                    key={st}
                    type="button"
                    onClick={() => setNewBet({ ...newBet, status: st as any })}
                    className={`flex-1 rounded-lg font-bold text-[10px] uppercase transition-all shadow-sm ${
                      newBet.status === st 
                        ? (st === 'won' ? 'bg-emerald-500 text-slate-900 shadow-emerald-500/20' : st === 'lost' ? 'bg-red-500 text-slate-900 shadow-red-500/20' : 'bg-slate-600 text-white')
                        : 'bg-slate-800 text-slate-500 hover:bg-slate-700'
                    }`}
                  >
                    {st === 'won' ? 'Win' : st === 'lost' ? 'Loss' : 'Pendente'}
                  </button>
                ))}
              </div>
            </div>

            <div className="md:col-span-2 lg:col-span-3 flex justify-end gap-3 mt-4">
              <button 
                type="button" 
                onClick={() => setIsFormOpen(false)}
                className="text-slate-500 hover:text-white px-6 py-2 transition-colors font-bold uppercase text-xs"
              >
                Cancelar
              </button>
              <button 
                type="submit" 
                className="bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-bold px-12 py-3 rounded-xl transition-all shadow-lg shadow-emerald-500/20 active:scale-95 uppercase text-sm"
              >
                Confirmar Operação
              </button>
            </div>
          </form>
        </Card>
      )}

      {/* Summary Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card className="flex items-center gap-5 bg-emerald-500/5 border-emerald-500/10 hover:bg-emerald-500/10 transition-colors">
          <div className="w-12 h-12 rounded-2xl bg-emerald-500/20 flex items-center justify-center text-emerald-400 text-xl shadow-inner">🏆</div>
          <div>
            <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Green Total</p>
            <p className="text-3xl font-black text-white">{bets.filter(b => b.status === 'won').length}</p>
          </div>
        </Card>
        <Card className="flex items-center gap-5 bg-red-500/5 border-red-500/10 hover:bg-red-500/10 transition-colors">
          <div className="w-12 h-12 rounded-2xl bg-red-500/20 flex items-center justify-center text-red-400 text-xl shadow-inner">🛑</div>
          <div>
            <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Red Total</p>
            <p className="text-3xl font-black text-white">{bets.filter(b => b.status === 'lost').length}</p>
          </div>
        </Card>
        <Card className="flex items-center gap-5 bg-slate-800/50 border-slate-700/30 hover:bg-slate-800 transition-colors">
          <div className="w-12 h-12 rounded-2xl bg-slate-700 flex items-center justify-center text-slate-400 text-xl shadow-inner">⌛</div>
          <div>
            <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Em Aberto</p>
            <p className="text-3xl font-black text-white">{bets.filter(b => b.status === 'pending').length}</p>
          </div>
        </Card>
      </div>

      {/* Filter Toolbar */}
      <div className="flex flex-col lg:flex-row justify-between items-center gap-4 bg-slate-800/40 p-4 rounded-2xl border border-slate-700/50 shadow-lg backdrop-blur-sm">
        <div className="flex p-1 bg-slate-900/50 rounded-xl gap-1">
          {[
            { id: 'all', label: 'Todos' },
            { id: 'won', label: 'Win', color: 'text-emerald-400', activeBg: 'bg-emerald-500/20' },
            { id: 'lost', label: 'Loss', color: 'text-red-400', activeBg: 'bg-red-500/20' },
            { id: 'pending', label: 'Abertas', color: 'text-slate-400', activeBg: 'bg-slate-700' }
          ].map((filter) => (
            <button
              key={filter.id}
              onClick={() => setStatusFilter(filter.id as any)}
              className={`px-5 py-2 rounded-lg text-xs font-bold uppercase transition-all ${
                statusFilter === filter.id 
                  ? (filter.activeBg || 'bg-slate-700') + ' ' + (filter.color || 'text-white') + ' shadow-sm'
                  : 'text-slate-500 hover:text-slate-300'
              }`}
            >
              {filter.label}
            </button>
          ))}
        </div>

        <div className="relative w-full lg:w-72 group">
          <input 
            type="text" 
            placeholder="Filtrar por jogo ou mercado..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded-xl pl-10 pr-10 py-2.5 text-sm text-white focus:border-emerald-500 outline-none transition-all shadow-inner group-hover:border-slate-600"
          />
          <svg className="absolute left-3.5 top-3 w-4 h-4 text-slate-500 group-focus-within:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
          {searchQuery && (
            <button 
              onClick={() => setSearchQuery('')}
              className="absolute right-3.5 top-3 text-slate-500 hover:text-white transition-colors"
            >
              ✖
            </button>
          )}
        </div>
      </div>

      {/* Table Content */}
      <div className="relative animate-in fade-in slide-in-from-bottom-4 duration-500">
         {statusFilter !== 'all' && (
           <div className="absolute -top-10 left-0">
             <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest flex items-center gap-2">
               <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
               Filtro Ativo: <span className="text-emerald-400 font-black">{statusFilter.toUpperCase()}</span>
             </span>
           </div>
         )}
         <BetHistoryTable dynamicBets={filteredBets} markets={markets} onUpdate={load} />
      </div>
    </div>
  );
};

export default BetsPage;

import React, { useState } from 'react';
import { Bet, Market } from '../../types';
import Card from '../Card';
import { api } from '../../services/api';

interface BetHistoryTableProps {
  dynamicBets?: Bet[];
  markets?: Market[];
  onUpdate?: () => void;
}

const BetHistoryTable: React.FC<BetHistoryTableProps> = ({ dynamicBets, markets = [], onUpdate }) => {
  const [editingBet, setEditingBet] = useState<Bet | null>(null);
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null);

  const displayBets = dynamicBets || [];

  const handleStatusChange = async (betId: string, status: Bet['status']) => {
    await api.updateBetStatus(betId, status);
    setActiveDropdown(null);
    if (onUpdate) onUpdate();
  };

  const handleDelete = async (betId: string) => {
    if (window.confirm('Excluir esta aposta? O capital será recalculado automaticamente.')) {
      await api.deleteBet(betId);
      if (onUpdate) onUpdate();
    }
  };

  const handleEditSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingBet) {
      await api.updateBet(editingBet.id, editingBet);
      setEditingBet(null);
      if (onUpdate) onUpdate();
    }
  };

  const getMetrics = (bet: Bet) => {
    const minute = bet.minute || 0;
    const implied = bet.odd > 0 ? (1 / bet.odd) * 100 : 0;
    const timeRemaining = Math.max(0, 90 - minute);
    const timeFactor = timeRemaining / 90;
    const adjustedImplied = minute > 0 ? implied * timeFactor : implied;

    const ev = ((bet.probability / 100) * bet.odd - 1) * 100;
    const fair = bet.probability > 0 ? (100 / bet.probability).toFixed(2) : '0.00';
    return { implied, adjustedImplied, ev, fair };
  };

  return (
    <Card className="p-0 overflow-hidden border-slate-700/50 shadow-2xl">
      <div className="flex justify-between items-center px-6 py-5 bg-slate-800/30 border-b border-slate-700/50">
        <h2 className="text-lg font-bold text-white flex items-center gap-2">
          <span className="text-emerald-400">📅</span> Histórico Operacional
        </h2>
        <div className="flex items-center gap-2">
           <span className="text-[10px] text-slate-400 uppercase font-black bg-slate-900/80 px-3 py-1.5 rounded-full border border-slate-700">
             {displayBets.length} Operações
           </span>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-sm text-left border-separate border-spacing-0">
          <thead className="text-[10px] text-slate-500 uppercase font-bold tracking-[0.15em] bg-slate-900/40">
            <tr>
              <th className="px-6 py-4 border-b border-slate-700">Data</th>
              <th className="px-6 py-4 border-b border-slate-700">Jogo / Evento</th>
              <th className="px-6 py-4 border-b border-slate-700">Mercado</th>
              <th className="px-6 py-4 border-b border-slate-700">Odd</th>
              <th className="px-6 py-4 border-b border-slate-700">Stake</th>
              <th className="px-6 py-4 border-b border-slate-700">EV</th>
              <th className="px-6 py-4 border-b border-slate-700">Profit</th>
              <th className="px-6 py-4 border-b border-slate-700">Status</th>
              <th className="px-6 py-4 border-b border-slate-700 text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {displayBets.length === 0 ? (
              <tr>
                <td colSpan={9} className="px-6 py-12 text-center text-slate-500 italic">
                   Nenhuma operação encontrada com os filtros atuais.
                </td>
              </tr>
            ) : displayBets.map((bet) => (
              <tr key={bet.id} className="hover:bg-slate-800/30 transition-all group">
                <td className="px-6 py-5 whitespace-nowrap text-slate-500 font-mono text-xs">
                  {new Date(bet.date).toLocaleDateString('pt-BR')}
                </td>
                <td className="px-6 py-5">
                  <span className="text-white font-bold block">{bet.game}</span>
                  {bet.minute !== undefined && bet.minute > 0 && (
                    <span className="text-[9px] text-slate-500 uppercase font-bold">Minuto: {bet.minute}'</span>
                  )}
                </td>
                <td className="px-6 py-5">
                  <span className="text-[10px] px-2 py-1 rounded bg-slate-900 border border-slate-700 text-slate-300 font-bold uppercase tracking-tight">
                    {bet.marketName}
                  </span>
                </td>
                <td className="px-6 py-5 font-mono text-xs text-slate-300">
                  @{bet.odd.toFixed(2)}
                </td>
                <td className="px-6 py-5 text-slate-400 font-mono text-xs">
                  R$ {bet.stake.toLocaleString()}
                </td>
                <td className={`px-6 py-5 font-mono text-xs font-black ${bet.ev >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                  {bet.ev >= 0 ? '+' : ''}{bet.ev.toFixed(1)}%
                </td>
                <td className={`px-6 py-5 font-black font-mono text-xs ${bet.profit > 0 ? 'text-emerald-400' : bet.profit < 0 ? 'text-red-400' : 'text-slate-600'}`}>
                  {bet.profit > 0 ? `+R$ ${bet.profit.toLocaleString()}` : bet.profit < 0 ? `-R$ ${Math.abs(bet.profit).toLocaleString()}` : 'R$ 0'}
                </td>
                <td className="px-6 py-5 relative">
                  <button 
                    onClick={() => setActiveDropdown(activeDropdown === bet.id ? null : bet.id)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all border shadow-sm ${
                      bet.status === 'won' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' :
                      bet.status === 'lost' ? 'bg-red-500/10 text-red-400 border-red-500/20' :
                      'bg-slate-700/50 text-slate-400 border-slate-600'
                    }`}
                  >
                    <span className={`w-1.5 h-1.5 rounded-full ${
                      bet.status === 'won' ? 'bg-emerald-500' : 
                      bet.status === 'lost' ? 'bg-red-500' : 
                      'bg-slate-400'
                    }`}></span>
                    {bet.status}
                    <span className="text-[7px] ml-1 opacity-50">▼</span>
                  </button>

                  {activeDropdown === bet.id && (
                    <>
                      <div className="fixed inset-0 z-40" onClick={() => setActiveDropdown(null)}></div>
                      <div className="absolute top-12 left-4 z-50 bg-slate-900 border border-slate-700 rounded-xl shadow-2xl py-2 min-w-[120px] animate-in fade-in zoom-in-95 duration-150 overflow-hidden">
                        <button onClick={() => handleStatusChange(bet.id, 'won')} className="w-full text-left px-4 py-2 text-[10px] font-bold text-emerald-400 hover:bg-emerald-400/10 uppercase flex items-center gap-2">
                           <span className="w-2 h-2 rounded-full bg-emerald-500"></span> Ganho (Won)
                        </button>
                        <button onClick={() => handleStatusChange(bet.id, 'lost')} className="w-full text-left px-4 py-2 text-[10px] font-bold text-red-400 hover:bg-red-400/10 uppercase flex items-center gap-2">
                           <span className="w-2 h-2 rounded-full bg-red-500"></span> Perda (Loss)
                        </button>
                        <button onClick={() => handleStatusChange(bet.id, 'pending')} className="w-full text-left px-4 py-2 text-[10px] font-bold text-slate-400 hover:bg-slate-800 uppercase flex items-center gap-2">
                           <span className="w-2 h-2 rounded-full bg-slate-500"></span> Pendente
                        </button>
                      </div>
                    </>
                  )}
                </td>
                <td className="px-6 py-5 text-right">
                   <div className="flex justify-end items-center gap-4 opacity-0 group-hover:opacity-100 transition-all translate-x-2 group-hover:translate-x-0">
                      <button onClick={() => setEditingBet(bet)} className="p-1.5 text-slate-500 hover:text-white hover:bg-slate-700 rounded-lg transition-colors" title="Editar">
                         <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"/></svg>
                      </button>
                      <button onClick={() => handleDelete(bet.id)} className="p-1.5 text-slate-500 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-colors" title="Excluir">
                         <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                      </button>
                   </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Modern Edit Modal */}
      {editingBet && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-md animate-in fade-in duration-200">
           <div className="bg-slate-900 border border-slate-700 w-full max-w-xl rounded-3xl p-8 shadow-2xl scale-in-center">
             <div className="flex justify-between items-start mb-8">
                <div>
                  <h3 className="text-2xl font-black text-white flex items-center gap-2">
                    <span className="text-emerald-400">✏️</span> Editar Operação
                  </h3>
                  <p className="text-slate-500 text-sm mt-1">Refine seus cálculos probabilísticos.</p>
                </div>
                <div className="bg-slate-950 px-5 py-3 rounded-2xl border border-slate-800 text-center shadow-inner">
                   <p className="text-[9px] text-slate-500 uppercase font-black tracking-widest mb-1">EV Ajustado</p>
                   <p className={`text-2xl font-black ${getMetrics(editingBet).ev >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                     {getMetrics(editingBet).ev >= 0 ? '+' : ''}{getMetrics(editingBet).ev.toFixed(1)}%
                   </p>
                </div>
             </div>

             <form onSubmit={handleEditSubmit} className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-500 uppercase px-1">Evento / Jogo</label>
                    <input 
                      type="text" 
                      value={editingBet.game}
                      onChange={(e) => setEditingBet({ ...editingBet, game: e.target.value })}
                      className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white text-sm outline-none focus:border-emerald-500 transition-all shadow-inner"
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-500 uppercase px-1">Mercado</label>
                    <select 
                      value={editingBet.marketId}
                      onChange={(e) => setEditingBet({ ...editingBet, marketId: e.target.value })}
                      className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white text-sm outline-none focus:border-emerald-500 cursor-pointer shadow-inner"
                    >
                      {markets.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                    </select>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 bg-slate-950/60 p-5 rounded-2xl border border-slate-800">
                   <div className="space-y-2">
                      <div className="flex justify-between items-center px-1">
                        <label className="text-[10px] font-bold text-slate-500 uppercase">Minuto</label>
                      </div>
                      <input 
                        type="number"
                        value={editingBet.minute || 0}
                        onChange={(e) => setEditingBet({ ...editingBet, minute: Number(e.target.value) })}
                        className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-white text-lg font-mono outline-none focus:border-emerald-500 shadow-inner"
                      />
                   </div>
                   <div className="space-y-2">
                      <div className="flex justify-between items-center px-1">
                        <label className="text-[10px] font-bold text-slate-500 uppercase">Odd</label>
                        <span className="text-[9px] text-slate-500">Imp: {getMetrics(editingBet).implied.toFixed(1)}%</span>
                      </div>
                      <input 
                        type="number" step="0.01"
                        value={editingBet.odd}
                        onChange={(e) => {
                          const val = Number(e.target.value);
                          setEditingBet({ ...editingBet, odd: val });
                        }}
                        className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-white text-lg font-mono outline-none focus:border-emerald-500 shadow-inner"
                      />
                   </div>
                   <div className="space-y-2">
                      <div className="flex justify-between items-center px-1">
                        <label className="text-[10px] font-bold text-emerald-500/70 uppercase">Sua Prob (%)</label>
                      </div>
                      <input 
                        type="number" step="0.1"
                        value={editingBet.probability}
                        onChange={(e) => setEditingBet({ ...editingBet, probability: Number(e.target.value) })}
                        className="w-full bg-slate-900 border border-emerald-500/30 rounded-xl px-4 py-3 text-emerald-400 text-lg font-mono outline-none focus:border-emerald-500 shadow-inner font-bold"
                      />
                      <p className="text-[8px] text-slate-500 mt-1 uppercase text-center">Ajustada: {getMetrics(editingBet).adjustedImplied.toFixed(1)}%</p>
                   </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                   <div className="space-y-1">
                      <label className="text-[10px] font-bold text-slate-500 uppercase px-1">Stake (R$)</label>
                      <input 
                        type="number"
                        value={editingBet.stake}
                        onChange={(e) => setEditingBet({ ...editingBet, stake: Number(e.target.value) })}
                        className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white text-sm font-mono outline-none focus:border-emerald-500 shadow-inner"
                      />
                   </div>
                   <div className="space-y-1">
                      <label className="text-[10px] font-bold text-slate-500 uppercase px-1">Data</label>
                      <input 
                        type="date"
                        value={editingBet.date}
                        onChange={(e) => setEditingBet({ ...editingBet, date: e.target.value })}
                        className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white text-sm outline-none focus:border-emerald-500 shadow-inner"
                      />
                   </div>
                </div>

                <div className="space-y-1">
                   <label className="text-[10px] font-bold text-slate-500 uppercase px-1">Resultado Final</label>
                   <div className="grid grid-cols-3 gap-2">
                     {['pending', 'won', 'lost'].map(st => (
                       <button 
                         key={st} type="button"
                         onClick={() => setEditingBet({ ...editingBet, status: st as any })}
                         className={`py-3 rounded-xl text-[10px] font-black uppercase transition-all shadow-sm ${
                            editingBet.status === st 
                            ? (st === 'won' ? 'bg-emerald-500 text-slate-950 shadow-emerald-500/20' : st === 'lost' ? 'bg-red-500 text-slate-950 shadow-red-500/20' : 'bg-slate-700 text-white')
                            : 'bg-slate-800 text-slate-500 hover:bg-slate-700'
                         }`}
                       >
                         {st}
                       </button>
                     ))}
                   </div>
                </div>

                <div className="flex gap-4 pt-4">
                  <button type="button" onClick={() => setEditingBet(null)} className="flex-1 bg-slate-800 hover:bg-slate-700 text-slate-400 py-4 rounded-2xl font-bold text-xs uppercase tracking-widest transition-all active:scale-95">Cancelar</button>
                  <button type="submit" className="flex-1 bg-emerald-500 hover:bg-emerald-400 text-slate-950 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-emerald-500/20 transition-all active:scale-95">Salvar Alterações</button>
                </div>
             </form>
           </div>
        </div>
      )}
    </Card>
  );
};

export default BetHistoryTable;

export interface Market {
  id: string;
  name: string;
  category: 'Gols' | 'Escanteios' | 'Cartões' | 'Handicap' | 'Resultado Final' | 'Resultado Correto' | 'Outros';
  type: 'Back' | 'Lay' | 'Ambos';
  isActive: boolean;
  createdAt: string;
}

export interface Bet {
  id: string;
  date: string;
  marketId: string; // Linked to Market.id
  marketName?: string; // Helper for display
  odd: number;
  stake: number;
  probability: number; // Estimated probability by the user (0-100)
  minute?: number; // Game minute at the time of the bet (0-90+)
  result: number;
  profit: number;
  ev: number; // Calculated EV percentage
  status: 'won' | 'lost' | 'pending';
  game: string;
}

export interface GrowthData {
  name: string;
  bank: number;
  projected?: number;
  growth?: number;
}

export interface WinRateData {
  name: string;
  value: number;
}

export interface BankrollConfig {
  initialBank: number;
  dailyInterest: number;
  periodDays: number;
}

export interface BankrollStats {
  current: number;
  initial: number;
  growthPct: number;
  drawdown: number;
  roi: number;
  totalProfit: number;
  todayProfit: number;
}

export interface ProjectionConfig {
  dailyTargetPct: number;
  horizonDays: number;
}

export interface MarketStats {
  marketId: string;
  marketName: string;
  roi: number;
  winRate: number;
  profit: number;
  evAverage: number;
  volume: number;
  drawdown: number;
  score: number;
  category: string;
}

import React, { useState, useEffect } from 'react';
import Card from '../components/Card';
import { api } from '../services/api';
import { MarketStats, Market } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, Legend } from 'recharts';

const MarketPage: React.FC = () => {
  const [stats, setStats] = useState<MarketStats[]>([]);
  const [markets, setMarkets] = useState<Market[]>([]);
  const [isRegistering, setIsRegistering] = useState(false);

  // Form State
  const [newName, setNewName] = useState('');
  const [newCategory, setNewCategory] = useState<Market['category']>('Gols');
  const [newType, setNewType] = useState<Market['type']>('Back');

  const loadData = async () => {
    const [s, m] = await Promise.all([api.getMarketStats(), api.getMarkets()]);
    setStats(s);
    setMarkets(m);
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleAddMarket = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName) return;
    await api.addMarket({
      name: newName,
      category: newCategory,
      type: newType,
      isActive: true
    });
    setNewName('');
    setIsRegistering(false);
    loadData();
  };

  const toggleStatus = async (id: string) => {
    await api.toggleMarketStatus(id);
    loadData();
  };

  return (
    <div className="flex flex-col gap-6">
      <header className="flex justify-between items-center mb-2">
        <div>
          <h1 className="text-3xl font-bold text-white">📊 Centro de Mercados</h1>
          <p className="text-slate-400">Gerencie tipos de apostas e analise sua vantagem estatística por categoria.</p>
        </div>
        <button 
          onClick={() => setIsRegistering(!isRegistering)}
          className="bg-emerald-500 hover:bg-emerald-600 text-slate-900 font-bold px-6 py-2 rounded-lg transition-all shadow-lg shadow-emerald-500/20"
        >
          {isRegistering ? 'Fechar' : '➕ Cadastrar Mercado'}
        </button>
      </header>

      {isRegistering && (
        <Card className="animate-in slide-in-from-top duration-300 border-emerald-500/30">
          <h2 className="text-lg font-bold text-white mb-4">Novo Mercado</h2>
          <form onSubmit={handleAddMarket} className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
            <div className="md:col-span-1">
              <label className="text-xs text-slate-500 uppercase mb-1 block">Nome do Mercado</label>
              <input 
                type="text" 
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                placeholder="Ex: Escanteios Over 9.5"
                className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-white outline-none focus:border-emerald-500"
              />
            </div>
            <div>
              <label className="text-xs text-slate-500 uppercase mb-1 block">Categoria</label>
              <select 
                value={newCategory}
                onChange={(e) => setNewCategory(e.target.value as any)}
                className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-white outline-none focus:border-emerald-500"
              >
                <option>Gols</option>
                <option>Escanteios</option>
                <option>Cartões</option>
                <option>Handicap</option>
                <option>Resultado Final</option>
                <option>Resultado Correto</option>
                <option>Outros</option>
              </select>
            </div>
            <div>
              <label className="text-xs text-slate-500 uppercase mb-1 block">Tipo</label>
              <select 
                value={newType}
                onChange={(e) => setNewType(e.target.value as any)}
                className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-white outline-none focus:border-emerald-500"
              >
                <option>Back</option>
                <option>Lay</option>
                <option>Ambos</option>
              </select>
            </div>
            <button type="submit" className="bg-emerald-500 text-slate-900 font-bold py-2 rounded hover:bg-emerald-400 transition-colors">
              Salvar
            </button>
          </form>
        </Card>
      )}

      {/* Quick Performance Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {stats.slice(0, 4).map((m, idx) => (
          <Card key={idx} className="relative overflow-hidden group border-l-4 border-emerald-500">
            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{m.category}</p>
            <h3 className="text-lg font-bold text-white mt-1">{m.marketName}</h3>
            <div className="mt-4 grid grid-cols-2 gap-2">
              <div>
                <p className="text-[10px] text-slate-500 uppercase">ROI</p>
                <p className={`text-lg font-bold ${m.roi >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>{m.roi.toFixed(1)}%</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-slate-500 uppercase">Win Rate</p>
                <p className="text-lg font-bold text-white">{m.winRate.toFixed(0)}%</p>
              </div>
            </div>
            <div className="mt-3 pt-3 border-t border-slate-700/50 flex justify-between items-center">
               <span className="text-xs text-slate-400">Score de Inteligência</span>
               <span className="text-sm font-bold text-emerald-400">{m.score.toFixed(0)}/100</span>
            </div>
          </Card>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Market List & Stats */}
        <Card className="lg:col-span-2">
          <h2 className="text-xl font-bold text-white mb-6">Ranking de Performance Real</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="text-xs text-slate-500 uppercase border-b border-slate-700">
                <tr>
                  <th className="px-4 py-3">Mercado</th>
                  <th className="px-4 py-3 text-right">ROI</th>
                  <th className="px-4 py-3 text-right">Volume</th>
                  <th className="px-4 py-3 text-right">Lucro</th>
                  <th className="px-4 py-3 text-right">Status</th>
                  <th className="px-4 py-3 text-right">Ações</th>
                </tr>
              </thead>
              <tbody>
                {markets.map((m) => {
                  const s = stats.find(st => st.marketId === m.id);
                  return (
                    <tr key={m.id} className="border-b border-slate-800/50 hover:bg-slate-800/30 transition-colors group">
                      <td className="px-4 py-4">
                        <p className="font-semibold text-white">{m.name}</p>
                        <p className="text-[10px] text-slate-500">{m.category} • {m.type}</p>
                      </td>
                      <td className={`px-4 py-4 text-right font-bold ${s && s.roi >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                        {s ? `${s.roi.toFixed(1)}%` : '-'}
                      </td>
                      <td className="px-4 py-4 text-right text-slate-400">{s ? s.volume : 0} ups</td>
                      <td className={`px-4 py-4 text-right font-mono ${s && s.profit >= 0 ? 'text-emerald-500' : 'text-red-500'}`}>
                        {s ? `R$ ${s.profit.toFixed(0)}` : 'R$ 0'}
                      </td>
                      <td className="px-4 py-4 text-right">
                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${m.isActive ? 'bg-emerald-500/10 text-emerald-400' : 'bg-slate-700 text-slate-500'}`}>
                          {m.isActive ? 'ATIVO' : 'INATIVO'}
                        </span>
                      </td>
                      <td className="px-4 py-4 text-right">
                         <button 
                          onClick={() => toggleStatus(m.id)}
                          className="text-xs text-slate-500 hover:text-white transition-colors underline"
                         >
                           {m.isActive ? 'Desativar' : 'Ativar'}
                         </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </Card>

        {/* Charts */}
        <div className="flex flex-col gap-6">
          <Card>
            <h2 className="text-lg font-bold text-white mb-6">ROI por Mercado</h2>
            <div className="h-[250px]">
              <ResponsiveContainer width="100%" height="100%">
