    status: 'pending' as Bet['status'],
    date: new Date().toISOString().split('T')[0],
  });

  const load = async () => {
    const [b, m, sc, bs] = await Promise.all([
      api.getBets(), 
      api.getMarkets(), 
      api.getStakeConfig(), 
      api.getBankrollStats()
    ]);
    setBets(b);
    const activeMarkets = m.filter(mark => mark.isActive);
