         odd: newBet.odd, 
         probability: newBet.probability, 
         marketId: initialMarketId 
       });
       setNewBet(prev => ({ ...prev, marketId: initialMarketId, stake: recommended || 100 }));
    }
  };

  useEffect(() => {
    load();
